from collections import deque

class Solution(object):
    def minMoves(self, classroom, energy):
        m, n = len(classroom), len(classroom[0])

        # Find start position and litter positions
        sr, sc = 0, 0
        litter_idx = {}
        litter_count = 0
        for r in range(m):
            for c in range(n):
                ch = classroom[r][c]
                if ch == 'S':
                    sr, sc = r, c
                elif ch == 'L':
                    litter_idx[(r, c)] = litter_count
                    litter_count += 1

        full_mask = (1 << litter_count) - 1

        # BFS state: (row, col, mask, energy_left)
        # bestEnergy[r][c][mask] = max energy seen at this state
        best = [[[-1] * (1 << litter_count) for _ in range(n)] for _ in range(m)]

        init_mask = 0
        best[sr][sc][init_mask] = energy
        q = deque([(sr, sc, init_mask, energy, 0)])

        dirs = [(-1,0),(1,0),(0,-1),(0,1)]

        while q:
            r, c, mask, eng, steps = q.popleft()

            if mask == full_mask:
                return steps

            if eng <= 0:
                continue

            for dr, dc in dirs:
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n and classroom[nr][nc] != 'X':
                    new_eng = eng - 1
                    new_mask = mask
                    cell = classroom[nr][nc]
                    if cell == 'L' and (nr, nc) in litter_idx:
                        bit = litter_idx[(nr, nc)]
                        new_mask = mask | (1 << bit)
                    elif cell == 'R':
                        new_eng = energy  # reset energy

                    # Only enqueue if this state has better energy than seen
                    if new_eng > best[nr][nc][new_mask]:
                        best[nr][nc][new_mask] = new_eng
                        q.append((nr, nc, new_mask, new_eng, steps + 1))

        return -1
